try {
  // ═══════════════════════════════════════════
  // LEER INPUT — viene de "Interpretar Imagen Producto"
  // ═══════════════════════════════════════════
  const inputData = $input.first()?.json || {};
  const rawAnalysis = inputData?.content || "";

  // Leer contexto del flujo
  let conversationId = "sin_id";
  let timestamp = String(Date.now());
  let accountId = "1";

  try {
    const extraerDatos = $('Extraer Datos del Mensaje1').first()?.json || {};
    conversationId = extraerDatos.conversationId || extraerDatos.chatId || "sin_id";
    timestamp = extraerDatos.timestamp || String(Date.now());
    accountId = extraerDatos.accountId || "1";
  } catch(e) {
    console.log('⚠️ No se pudo leer Extraer Datos del Mensaje1:', e.message);
  }

  console.log('🖼️ conversationId:', conversationId);
  console.log('🖼️ Raw analysis (primeros 200):', rawAnalysis.substring(0, 200));

  // ═══════════════════════════════════════════
  // LIMPIAR BACKTICKS
  // ═══════════════════════════════════════════
  const cleanJson = rawAnalysis
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();

  console.log('🧹 JSON limpio:', cleanJson.substring(0, 200));

  // ═══════════════════════════════════════════
  // PARSEAR JSON
  // ═══════════════════════════════════════════
  let analysisData = {};

  try {
    analysisData = JSON.parse(cleanJson);
    console.log('✅ JSON parseado. tipo:', analysisData.tipo);
  } catch (e) {
    console.log('⚠️ No es JSON válido:', e.message);
    const tipoMatch = cleanJson.match(/"tipo"\s*:\s*"([^"]+)"/);
    if (tipoMatch) {
      analysisData.tipo = tipoMatch[1];
      console.log('🔧 Tipo extraído con regex:', analysisData.tipo);
    }
  }

  // ═══════════════════════════════════════════
  // CLASIFICAR
  // ═══════════════════════════════════════════
  const tipo = (analysisData.tipo || '').toUpperCase();

  const esPez         = tipo === 'PEZ';
  const esPlanta      = tipo === 'PLANTA';
  const esEquipo      = tipo === 'EQUIPO';
  const esComprobante = tipo === 'COMPROBANTE';

  // Campos comunes
  const descripcion      = analysisData.descripcion      || '';
  const colores          = (analysisData.colores          || []).join(', ') || 'no identificados';
  const caracteristicas  = (analysisData.caracteristicas  || []).join(', ');
  const precios_visibles = analysisData.precios_visibles  || [];
  const preciosTexto     = precios_visibles.length > 0
    ? `Precios visibles en la imagen: ${precios_visibles.join(' | ')}`
    : 'No hay precios visibles en la imagen.';

  let finalContent = '';

  // ─── COMPROBANTE ───────────────────────────
  if (esComprobante) {
    finalContent = `[COMPROBANTE_DE_PAGO_DETECTADO]
Descripción: ${descripcion.substring(0, 300)}
Acción requerida: Usar herramienta verificar_pago`;

  // ─── PEZ ───────────────────────────────────
  } else if (esPez) {
    const especie  = analysisData.especie   || null;
    const familia  = analysisData.familia   || 'otro';
    const tipo_agua = analysisData.tipo_agua || 'dulce_tropical';
    const cantidad = analysisData.cantidad_aparente || '1';

    finalContent = `[IMAGEN_DE_PEZ_DETECTADA]
El cliente envió una imagen con peces. Busca disponibilidad con buscar_producto:

- Especie: ${especie || 'No identificada — ver descripción'}
- Familia: ${familia}
- Tipo de agua: ${tipo_agua}
- Colores: ${colores}
- Características: ${caracteristicas || 'no especificadas'}
- Cantidad visible: ${cantidad}
- ${preciosTexto}
- Descripción completa: ${descripcion}

INSTRUCCIÓN PARA EL AGENTE:
1. Llama buscar_producto con especie="${especie || ''}", familia="${familia}", tipo_agua="${tipo_agua}"
2. Si los precios visibles coinciden con tu catálogo, confírmalo al cliente
3. Si no hay stock, ofrece encargo
4. NUNCA inventes precio ni disponibilidad — usa SOLO lo que retorne buscar_producto`;

  // ─── PLANTA ────────────────────────────────
  } else if (esPlanta) {
    const especie       = analysisData.especie || null;
    const requerimiento = caracteristicas || 'no especificado';

    finalContent = `[IMAGEN_DE_PLANTA_DETECTADA]
El cliente envió una imagen de planta acuática.

- Especie: ${especie || 'No identificada'}
- Requerimiento: ${requerimiento}
- Colores: ${colores}
- ${preciosTexto}
- Descripción: ${descripcion}

INSTRUCCIÓN PARA EL AGENTE:
1. Llama buscar_producto con especie="${especie || ''}", tipo="planta"
2. Si hay precio visible en la imagen, contrástalo con tu catálogo
3. NUNCA inventes precio ni disponibilidad`;

  // ─── EQUIPO ────────────────────────────────
  } else if (esEquipo) {
    const subfamilia = analysisData.familia || 'accesorio';

    finalContent = `[IMAGEN_DE_EQUIPO_DETECTADA]
El cliente envió una imagen de equipo o accesorio de acuario.

- Tipo: ${subfamilia}
- Colores: ${colores}
- ${preciosTexto}
- Descripción: ${descripcion}

INSTRUCCIÓN PARA EL AGENTE:
1. Llama buscar_producto con tipo="${subfamilia}"
2. Si hay precio visible, contrástalo con tu catálogo
3. NUNCA inventes precio ni disponibilidad`;

  // ─── OTRO ──────────────────────────────────
  } else {
    finalContent = `El cliente envió una imagen que no corresponde a un producto reconocido (${descripcion || 'imagen no identificada'}).
Responde amablemente preguntando qué pez, planta o equipo le interesa, o que envíe una foto más clara del producto.`;
    console.log('⚠️ Imagen clasificada como OTRO:', descripcion);
  }

  console.log('✅ finalContent (primeros 150):', finalContent.substring(0, 150));

  return [{
    json: {
      content: finalContent,
      timestamp: timestamp,
      conversation_id: conversationId,
      account_id: accountId,
      is_comprobante: esComprobante,
      is_pez: esPez,
      is_planta: esPlanta,
      is_equipo: esEquipo,
      precios_visibles: precios_visibles,
      especie_detectada: analysisData.especie || null,
      familia_detectada: analysisData.familia || null,
      original_analysis: rawAnalysis
    }
  }];

} catch (error) {
  console.error('❌ ERROR CRÍTICO:', error.message);

  let conversationFallback = "fallback";
  let accountFallback = "1";
  try {
    const fb = $('Extraer Datos del Mensaje1').first()?.json || {};
    conversationFallback = fb.conversationId || fb.chatId || "fallback";
    accountFallback = fb.accountId || "1";
  } catch(e) {}

  return [{
    json: {
      content: "El cliente envió una imagen. Pídele que describa qué pez, planta o equipo le interesa.",
      timestamp: String(Date.now()),
      conversation_id: conversationFallback,
      account_id: accountFallback,
      is_comprobante: false,
      is_pez: false,
      is_planta: false,
      is_equipo: false,
      precios_visibles: [],
      especie_detectada: null,
      familia_detectada: null,
      error: true,
      error_message: error.message
    }
  }];
}

