// Parse AI Agent JSON output with fallback for old-format agents
const raw = $input.first().json.output || $input.first().json.text || "";
let parsed;
try {
  // Try to find JSON in the response
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    parsed = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error("No JSON found");
  }
} catch (e) {
  // Fallback: old tag-based format for backward compatibility
  const isEscalar = /\[ESCALAR\]/i.test(raw);
  const imgMatch = raw.match(/\[IMG:(.*?)\]/);
  const docMatch = raw.match(/\[DOC:(.*?)\]/);

  let action = "text";
  let media = [];
  let text = raw.replace(/\[ESCALAR\]/gi, "").replace(/\[IMG:.*?\]/g, "").replace(/\[DOC:.*?\]/g, "").trim();

  if (isEscalar) action = "escalate";
  else if (imgMatch) {
    action = "image";
    media.push({ type: "image", url: imgMatch[1], caption: "" });
  }
  else if (docMatch) {
    action = "document";
    media.push({ type: "document", url: docMatch[1], caption: "" });
  }

  parsed = { text, action, media };
}

return [{ json: parsed }];

const agentData = $input.first().json;
const senderPhone = $('Extraer Datos del Mensaje1').first().json.phoneNumber ?? '';
const agentStatus = agentData.agent_status ?? 'active';
const adminPhone = agentData.admin_phone ?? '';
const SUPERADMIN_PHONE = '+573016050818';

// If agent is in production mode, allow all messages
if (agentStatus === 'active') {
  return [{ json: { ...agentData, allowed: true } }];
}

// If agent is inactive, block all
if (agentStatus === 'inactive') {
  return [{ json: { ...agentData, allowed: false } }];
}

// setup or testing mode: only allow admin and superadmin
const normalize = (p) => p.replace(/[^0-9]/g, '');
const senderNorm = normalize(senderPhone);
const adminNorm = normalize(adminPhone);
const superNorm = normalize(SUPERADMIN_PHONE);

const isAdmin = senderNorm.length > 0 && (senderNorm === adminNorm || senderNorm.endsWith(adminNorm.slice(-10)) || adminNorm.endsWith(senderNorm.slice(-10)));
const isSuperAdmin = senderNorm.length > 0 && (senderNorm === superNorm || senderNorm.endsWith(superNorm.slice(-10)) || superNorm.endsWith(senderNorm.slice(-10)));

if (isAdmin || isSuperAdmin) {
  return [{ json: { ...agentData, allowed: true } }];
}

// Not allowed
return [{ json: { ...agentData, allowed: false } }];
